import axios from 'axios';
import React from 'react';

const Account = () => {
    const CURRENCY_CODE = {
        USD: 'USD',
        ILS: 'ILS',
        EUR: 'EUR',
        RUB: 'RUB'
    }
    const getDateToday = () => {
        const date = new Date;
        return `${date.getFullYear()}-${date.getMonth() + 1}-${date.getDate()}`;
    }

    const renderContent = (response) => {
        let content = document.getElementById('data').innerHTML;
        const { data } = response;
        Object.keys(data.rates).map((currecyCode) => {
            content = `
            <td>
                <tr>${data.base}</tr>
                <tr>${data.rates[currecyCode]}</tr>
            </td>
            `
        })

        document.getElementById('data').innerHTML = content;
    }

    axios.get(`https://api.ratesapi.io/api/${getDateToday()}?base=${CURRENCY_CODE.USD}&symbols=${CURRENCY_CODE.ILS},${CURRENCY_CODE.RUB}`)
        .then(renderContent);

    return <React.Fragment>
        <div className="content" >
            <div className="container">
                <div className="content__header">
                    <span className="content__header-title">- My account -</span>
                </div>
                <div className="content__body">
                   <div id="data"></div>
                </div>
            </div>
        </div>
    </React.Fragment>
}

export default Account;
